import java.util.HashMap;
import java.util.Map;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int M = scanner.nextInt();
        Map<String, String> chefCountry = new HashMap<>();
        Map<String, Integer> votes = new HashMap<>();
        for (int i = 0; i < N; i++) {
            String chef = scanner.next();
            String country = scanner.next();
            chefCountry.put(chef, country);
            votes.put(chef, 0);
        }
        for (int i = 0; i < M; i++) {
            String email = scanner.next();
            votes.put(email, votes.get(email) + 1);
        }
        String maxCountry = "";
        int maxVotes = 0;
        for (Map.Entry<String, String> entry : chefCountry.entrySet()) {
            String country = entry.getValue();
            int countryVotes = 0;
            for (Map.Entry<String, String> entry2 : chefCountry.entrySet()) {
                if (entry2.getValue().equals(country)) {
                    countryVotes += votes.get(entry2.getKey());
                }
            }
            if (countryVotes > maxVotes) {
                maxVotes = countryVotes;
                maxCountry = country;
            } else if (countryVotes == maxVotes) {
                if (country.compareTo(maxCountry) < 0) {
                    maxCountry = country;
                }
            }
        }
        System.out.println(maxCountry);
        String maxChef = "";
        int maxChefVotes = 0;
        for (Map.Entry<String, Integer> entry : votes.entrySet()) {
            if (entry.getValue() > maxChefVotes) {
                maxChefVotes = entry.getValue();
                maxChef = entry.getKey();
            } else if (entry.getValue() == maxChefVotes) {
                if (entry.getKey().compareTo(maxChef) < 0) {
                    maxChef = entry.getKey();
                }
            }
        }
        System.out.println(maxChef);
    }
}

